itSScopeAttributes* it_80291CCC(Item_GObj* gobj, Vec3* pos)
{
    itSScopeAttributes* attrs = GET_ATTRS(GET_ITEM(gobj));
    pos->x = attrs->x34.x;
    pos->y = attrs->x34.y;
    pos->z = attrs->x34.z;
    return attrs;
}

s32 it_80291CF4(Item_GObj* gobj, s32 arg1)
{
    itSScopeAttributes* attrs = GET_ATTRS(GET_ITEM(gobj));

    if (arg1 <= attrs->x4) {
        return 0;
    }
    if (arg1 < attrs->x8 * 8) {
        return arg1 / 8;
    }
    return 9;
}

