void it_80291F14(Item_GObj* gobj, int charge_level)
{
    Item* ip = GET_ITEM(gobj);
    itSScopeAttributes* attrs = GET_ATTRS(ip);
    int cost = charge_level;

    switch (charge_level) {
    case 0:
        cost = (int) attrs->xC[0];
        break;
    case 1:
    case 2:
    case 3:
    case 4:
    case 5:
    case 6:
    case 7:
    case 8:
        cost = (int) attrs->xC[charge_level];
        break;
    case 9:
